--- /dev/null
+++ b/src/services/priority-router.ts
@@ -0,0 +1,38 @@
+/**
+ * Priority router — routes notifications to the appropriate channel based on priority.
+ *
+ * Routing rules:
+ * - urgent  → sms
+ * - normal  → email
+ * - low     → webhook
+ *
+ * This replaces the previous broadcast approach where all notifications were sent
+ * to the email channel. Priority-based routing ensures urgent notifications reach
+ * users via the fastest channel (SMS), while lower-priority notifications use
+ * less intrusive channels.
+ */
+
+export type NotificationPriority = 'urgent' | 'normal' | 'low';
+
+const PRIORITY_CHANNEL_MAP: Record<NotificationPriority, string> = {
+  urgent: 'sms',
+  normal: 'email',
+  low: 'webhook',
+};
+
+export function resolveChannel(priority: NotificationPriority): string {
+  const channel = PRIORITY_CHANNEL_MAP[priority];
+  if (!channel) {
+    throw new Error(`Unknown notification priority: ${priority}`);
+  }
+  return channel;
+}
+
+export class PriorityRouter {
+  /**
+   * Resolve the delivery channel for a given notification priority.
+   */
+  route(priority: NotificationPriority): string {
+    return resolveChannel(priority);
+  }
+}

