+/**
+ * SMS channel handler — listens for notification events and delivers via SMS.
+ *
+ * Depends on:
+ * - EventBus (event system) for receiving notification events
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { NotificationRequestedEvent } from '../events/event-types.js';
+import { Logger } from '../utils/logger.js';
+
+export interface DeliveredSms {
+  id: string;
+  recipient: string;
+  subject: string;
+  body: string;
+  deliveredAt: Date;
+}
+
+let nextSmsId = 1;
+
+function generateSmsId(): string {
+  return `sms-${String(nextSmsId++).padStart(4, '0')}`;
+}
+
+export function resetSmsIdCounter(): void {
+  nextSmsId = 1;
+}
+
+export class SmsChannelHandler {
+  private logger = new Logger('SmsChannelHandler');
+  private deliveredMessages: DeliveredSms[] = [];
+
+  constructor(private eventBus: EventBus) {
+    this.eventBus.on<NotificationRequestedEvent>(
+      'notification:requested',
+      (event) => this.handleNotification(event),
+    );
+  }
+
+  private handleNotification(event: NotificationRequestedEvent): void {
+    if (event.channel !== 'sms') {
+      return;
+    }
+
+    const sms: DeliveredSms = {
+      id: generateSmsId(),
+      recipient: event.recipient,
+      subject: event.subject,
+      body: event.body,
+      deliveredAt: new Date(),
+    };
+
+    this.deliveredMessages.push(sms);
+    this.logger.info(`SMS delivered: ${sms.id} to ${sms.recipient}`);
+  }
+
+  getDeliveredMessages(): DeliveredSms[] {
+    return [...this.deliveredMessages];
+  }
+
+  getDeliveredMessagesForRecipient(recipient: string): DeliveredSms[] {
+    return this.deliveredMessages.filter((m) => m.recipient === recipient);
+  }
+
+  clearDeliveredMessages(): void {
+    this.deliveredMessages = [];
+  }
+}

