/**
 * SMS channel handler — listens for notification events and delivers via SMS.
 *
 * Depends on:
 * - EventBus (event system) for receiving notification events
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationRequestedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface DeliveredSms {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  deliveredAt: Date;
}

let nextSmsId = 1;

function generateSmsId(): string {
  return `sms-${String(nextSmsId++).padStart(4, '0')}`;
}

export function resetSmsIdCounter(): void {
  nextSmsId = 1;
}

export class SmsChannelHandler {
  private logger = new Logger('SmsChannelHandler');
  private deliveredMessages: DeliveredSms[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>(
      'notification:requested',
      (event) => this.handleNotification(event),
    );
  }

  private handleNotification(event: NotificationRequestedEvent): void {
    if (event.channel !== 'sms') {
      return;
    }

    const sms: DeliveredSms = {
      id: generateSmsId(),
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      deliveredAt: new Date(),
    };

    this.deliveredMessages.push(sms);
    this.logger.info(`SMS delivered: ${sms.id} to ${sms.recipient}`);
  }

  getDeliveredMessages(): DeliveredSms[] {
    return [...this.deliveredMessages];
  }

  getDeliveredMessagesForRecipient(recipient: string): DeliveredSms[] {
    return this.deliveredMessages.filter((m) => m.recipient === recipient);
  }

  clearDeliveredMessages(): void {
    this.deliveredMessages = [];
  }
}

/**
 * Webhook channel handler — listens for notification events and delivers via webhook.
 *
 * Depends on:
 * - EventBus (event system) for receiving notification events
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationRequestedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface DeliveredWebhook {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  deliveredAt: Date;
}

let nextWebhookId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounter(): void {
  nextWebhookId = 1;
}

export class WebhookChannelHandler {
  private logger = new Logger('WebhookChannelHandler');
  private deliveredWebhooks: DeliveredWebhook[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>(
      'notification:requested',
      (event) => this.handleNotification(event),
    );
  }

  private handleNotification(event: NotificationRequestedEvent): void {
    if (event.channel !== 'webhook') {
      return;
    }

    const webhook: DeliveredWebhook = {
      id: generateWebhookId(),
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      deliveredAt: new Date(),
    };

    this.deliveredWebhooks.push(webhook);
    this.logger.info(`Webhook delivered: ${webhook.id} to ${webhook.recipient}`);
  }

  getDeliveredWebhooks(): DeliveredWebhook[] {
    return [...this.deliveredWebhooks];
  }

  getDeliveredWebhooksForRecipient(recipient: string): DeliveredWebhook[] {
    return this.deliveredWebhooks.filter((w) => w.recipient === recipient);
  }

  clearDeliveredWebhooks(): void {
    this.deliveredWebhooks = [];
  }
}

/**
 * Priority router — routes notifications to the appropriate channel based on priority.
 *
 * Routing rules:
 * - urgent  → sms
 * - normal  → email
 * - low     → webhook
 *
 * This replaces the previous broadcast approach where all notifications were sent
 * to the email channel. Priority-based routing ensures urgent notifications reach
 * users via the fastest channel (SMS), while lower-priority notifications use
 * less intrusive channels.
 */

export type NotificationPriority = 'urgent' | 'normal' | 'low';

const PRIORITY_CHANNEL_MAP: Record<NotificationPriority, string> = {
  urgent: 'sms',
  normal: 'email',
  low: 'webhook',
};

export function resolveChannel(priority: NotificationPriority): string {
  const channel = PRIORITY_CHANNEL_MAP[priority];
  if (!channel) {
    throw new Error(`Unknown notification priority: ${priority}`);
  }
  return channel;
}

export class PriorityRouter {
  /**
   * Resolve the delivery channel for a given notification priority.
   */
  route(priority: NotificationPriority): string {
    return resolveChannel(priority);
  }
}

