/**
 * Dispatch a notification via the EventBus and record it locally.
 * The channel is resolved from the priority via the PriorityRouter.
 */
private async sendNotification(params: {
  priority: NotificationPriority;
  recipient: string;
  subject: string;
  body: string;
}): Promise<void> {
  const channel = this.priorityRouter.route(params.priority);

  const notification: Notification = {
    id: generateNotificationId(),
    channel,
    priority: params.priority,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    sentAt: new Date(),
  };
  this.notifications.push(notification);

  const event: NotificationRequestedEvent = {
    type: 'notification:requested',
    channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    timestamp: new Date(),
  };
  await this.eventBus.emit(event);

  this.logger.info(`Notification sent: ${notification.id} via ${channel} (priority: ${params.priority}) to ${params.recipient}`);
}

/**
 * Send an ad-hoc notification (not triggered by a domain event).
 * Priority determines which channel the notification is routed to:
 *   urgent → sms, normal → email, low → webhook
 */
async notify(params: {
  priority: NotificationPriority;
  recipient: string;
  subject: string;
  body: string;
}): Promise<void> {
  await this.sendNotification(params);
}

